// Aggregate ingredients from a week plan with per-recipe servings
function computeShoppingList(plan, servings) {
  const totals = {};
  plan.forEach((day, dayIdx) => {
    ["breakfast","lunch","dinner"].forEach(slot => {
      const recipe = day[slot];
      if (!recipe) return;                               // ← skip null slots
      const ings   = RECIPE_INGREDIENTS[recipe.id] || [];
      const srv    = servings[`${dayIdx}-${slot}`] || 1;
      ings.forEach(ing => {
        const key = ing.name;
        if (!totals[key]) {
          totals[key] = { ...ing, totalQty: 0, sources: [] };
        }
        totals[key].totalQty += ing.qty * srv;
        totals[key].sources.push({ label: `${day.short} ${slot === "breakfast" ? "☀️" : slot === "lunch" ? "🌤" : "🌙"}`, qty: ing.qty * srv, unit: ing.unit });
      });
    });
  });
  // Round nicely
  Object.values(totals).forEach(v => {
    v.totalQty = Math.round(v.totalQty * 10) / 10;
  });
  return totals;
}

// ─────────────────────────────────────────────────────────────────────────────
// src/hooks/useMealPlan  — Undo Engine (H3 User Control)
// ─────────────────────────────────────────────────────────────────────────────
function useMealPlan() {
  const [plan,       setPlan]       = useState(generateWeekPlan);
  const [snackbar,   setSnackbar]   = useState(null);   // { message, countdown }
  const [isLoading,  setIsLoading]  = useState(false);
  const undoRef  = useRef(null);
  const timerRef = useRef(null);
  const countRef = useRef(null);

  const clearUndo = () => {
    clearTimeout(timerRef.current);
    clearInterval(countRef.current);
    undoRef.current = null;
  };

  const showSnackbar = (msg, prevPlan) => {
    clearUndo();
    undoRef.current = prevPlan;
    let cd = 10;
    setSnackbar({ message: msg, countdown: cd });
    countRef.current = setInterval(() => {
      cd -= 1;
      setSnackbar(s => s ? { ...s, countdown: cd } : null);
      if (cd <= 0) { clearInterval(countRef.current); setSnackbar(null); }
    }, 1000);
    timerRef.current = setTimeout(() => { setSnackbar(null); undoRef.current = null; }, 10000);
  };

  const undo = () => {
    if (undoRef.current) { setPlan(undoRef.current); clearUndo(); setSnackbar(null); }
  };

  const swapMeal = (dayIdx, slot, recipe = null) => {
    setPlan(prev => {
      const newRecipe = recipe || RECIPES[Math.floor(Math.random() * RECIPES.length)];
      showSnackbar("Comida actualizada.", prev);
      return prev.map((d, i) => i === dayIdx
        ? { ...d, [slot]: newRecipe }
        : d);
    });
  };

  const regenerate = () => {
    setIsLoading(true);
    const prev = plan;
    setTimeout(() => {
      setPlan(generateWeekPlan());
      setIsLoading(false);
      showSnackbar("Tu semana ya está lista.", prev);
    }, 2200);
  };

  useEffect(() => () => clearUndo(), []);

  return { plan, swapMeal, regenerate, isLoading, snackbar, undo };
}

// ─────────────────────────────────────────────────────────────────────────────
// src/hooks/useStepTimer  — Play/Pause/Reset per recipe step
// ─────────────────────────────────────────────────────────────────────────────
function useStepTimer(initialSeconds) {
  const [remaining, setRemaining] = useState(initialSeconds);
  const [running,   setRunning]   = useState(false);
  const ref = useRef(null);

  useEffect(() => {
    if (running) {
      ref.current = setInterval(() => {
        setRemaining(r => { if (r <= 1) { clearInterval(ref.current); setRunning(false); return 0; } return r - 1; });
      }, 1000);
    } else clearInterval(ref.current);
    return () => clearInterval(ref.current);
  }, [running]);

  const toggle = () => { if (remaining > 0) setRunning(r => !r); };
  const reset  = () => { setRunning(false); setRemaining(initialSeconds); };
  const pct    = 1 - remaining / initialSeconds;

  const fmt = (s) => `${String(Math.floor(s/60)).padStart(2,"0")}:${String(s%60).padStart(2,"0")}`;

  return { remaining, running, toggle, reset, pct, fmt };
}

// ─────────────────────────────────────────────────────────────────────────────
// src/components/StepTimer
// ─────────────────────────────────────────────────────────────────────────────
function StepTimer({ seconds }) {
  const { remaining, running, toggle, reset, pct, fmt } = useStepTimer(seconds);
  const done = remaining === 0;
  const r = 18, circ = 2 * Math.PI * r;

  return (
    <div style={{ display:"flex", alignItems:"center", gap:10, marginTop:8,
      background: done ? T.greenPale : running ? T.orangePale : T.surface,
      borderRadius:12, padding:"10px 12px", transition:"background 0.4s",
      border:`1px solid ${done ? T.green+"40" : running ? T.orange+"40" : T.border}` }}>
      {/* Arc progress */}
      <svg width={40} height={40} style={{ flexShrink:0 }}>
        <circle cx={20} cy={20} r={r} fill="none" stroke={T.border} strokeWidth={3} />
        <circle cx={20} cy={20} r={r} fill="none"
          stroke={done ? T.green : running ? T.orange : T.inkGhost}
          strokeWidth={3} strokeLinecap="round"
          strokeDasharray={circ}
          strokeDashoffset={circ * (1 - pct)}
          transform="rotate(-90 20 20)"
          style={{ transition:"stroke-dashoffset 0.9s linear, stroke 0.4s" }} />
        <text x={20} y={24} textAnchor="middle" fontSize={9} fontWeight={700}
          fill={done ? T.green : running ? T.orange : T.inkLight}>
          {done ? "✓" : fmt(remaining)}
        </text>
      </svg>
      {/* Time label + reset on left side */}
      <div style={{ flex:1 }}>
        <div style={{ fontSize:12, fontWeight:700, color: done ? T.green : T.ink }}>
          {done ? "¡Listo! 🎉" : running ? "Te avisaremos cuando esté listo." : "Toca ▶ para empezar"}
        </div>
        <div style={{ display:"flex", alignItems:"center", gap:6, marginTop:2 }}>
          <span style={{ fontSize:11, color:T.inkLight }}>{fmt(seconds)}</span>
          {/* Reset — left, next to time */}
          <button onClick={reset} aria-label="Reiniciar temporizador"
            style={{ background:"none", border:"none", cursor:"pointer", padding:0,
              display:"flex", alignItems:"center" }}>
            <RotateCcw size={13} color={T.inkLight} strokeWidth={2}/>
          </button>
        </div>
      </div>
      {/* Play/pause only on right */}
      <button onClick={toggle} disabled={done}
        aria-label={running ? "Pausar" : "Iniciar"}
        style={{ background: running ? T.orangePale : T.orange,
          color: running ? T.orange : T.ink,
          border: running ? `2px solid ${T.orange}` : "none",
          borderRadius:R.L, width:44, height:44, fontSize:18, cursor: done ? "not-allowed" : "pointer",
          display:"flex", alignItems:"center", justifyContent:"center",
          opacity: done ? 0.4 : 1, boxShadow: done || running ? "none" : EL.S,
          flexShrink:0 }}>
        {running ? <Pause size={18} color={T.orange} strokeWidth={2}/> : <Play size={18} color={T.ink} strokeWidth={2}/>}
      </button>
    </div>
  );
}

// ─────────────────────────────────────────────────────────────────────────────
// src/components/ConfirmationModal  — Error Prevention (H5)
// ─────────────────────────────────────────────────────────────────────────────
function ConfirmationModal({ visible, onConfirm, onCancel }) {
  if (!visible) return null;
  return (
    <div style={{ position:"fixed", inset:0, zIndex:200, display:"flex",
      alignItems:"flex-end", justifyContent:"center",
      background:"rgba(10,20,10,0.55)", backdropFilter:"blur(6px)" }}>
      <div style={{ background:T.card, borderRadius:"28px 28px 0 0", padding:"28px 24px 40px",
        width:"100%", maxWidth:430, boxShadow:"0 -16px 64px rgba(0,0,0,0.18)",
        animation:"slideUp 0.3s cubic-bezier(0.34,1.56,0.64,1)" }}>
        <div style={{ width:36, height:4, borderRadius:99, background:T.border, margin:"0 auto 24px" }} />
        <div style={{ textAlign:"center", marginBottom:28 }}>
          <div style={{ width:64, height:64, borderRadius:20, background:T.yellowPale,
            display:"flex", alignItems:"center", justifyContent:"center",
            fontSize:32, margin:"0 auto 16px" }}>✨</div>
          <h3 style={{ margin:"0 0 10px", fontSize:22, fontWeight:400, color:T.ink,
            fontFamily:"'DM Sans', sans-serif", letterSpacing:0.2 }}>
            ¿Probar nuevas ideas?
          </h3>
          <p style={{ margin:0, color:T.inkLight, fontSize:14, lineHeight:1.65 }}>
            Actualizaremos las comidas de <strong style={{ color:T.ink }}>toda la semana</strong> con un plan nuevo.
            Puedes deshacer en 10 segundos si prefieres volver al anterior.
          </p>
        </div>
        <div style={{ display:"flex", flexDirection:"column", gap:10 }}>
          <PrimaryBtn onClick={onConfirm}>Sí, probar nuevas ideas ✨</PrimaryBtn>
          <GhostBtn onClick={onCancel}>Mantener plan actual</GhostBtn>
        </div>
      </div>
    </div>
  );
}

// ─────────────────────────────────────────────────────────────────────────────
// src/components/Snackbar  — Undo toaster
// ─────────────────────────────────────────────────────────────────────────────
function Snackbar({ snackbar, onUndo }) {
  const show = !!snackbar;
  return (
    <div style={{ position:"fixed", bottom:88, left:"50%",
      transform:`translateX(-50%) translateY(${show ? 0 : 100}px)`,
      opacity: show ? 1 : 0, transition:"all 0.4s cubic-bezier(0.34,1.56,0.64,1)",
      zIndex:150, pointerEvents: show ? "auto" : "none",
      background:T.ink, borderRadius:16, padding:"12px 16px",
      display:"flex", alignItems:"center", gap:12,
      boxShadow:"0 8px 32px rgba(0,0,0,0.28)", minWidth:280, maxWidth:360 }}>
      <div style={{ flex:1 }}>
        <span style={{ color:"#fff", fontSize:13, fontWeight:600 }}>
          {snackbar?.message}
        </span>
        {snackbar?.countdown > 0 && (
          <span style={{ color:"rgba(255,255,255,0.75)", fontSize:12, marginLeft:6 }}>
            · {snackbar.countdown}s
          </span>
        )}
      </div>
      <button onClick={onUndo} style={{ background:T.orange, border:"none", color:T.ink,
        borderRadius:10, padding:"7px 14px", fontSize:13, fontWeight:800,
        cursor:"pointer", letterSpacing:0.3 }}>Deshacer</button>
    </div>
  );
}

