function PrimaryBtn({ children, onClick, small, disabled }) {
  return (
    <button onClick={onClick} disabled={disabled} style={{
      background: disabled ? T.border : T.orange,
      color: disabled ? T.inkGhost : T.ink, border:"none",
      borderRadius: small ? 10 : 14, padding: small ? "8px 16px" : "14px 24px",
      fontSize: small ? 12 : 15, fontWeight:800, cursor: disabled ? "not-allowed" : "pointer",
      boxShadow: disabled ? "none" : `0 4px 18px ${T.orange}60`,
      transition:"all 0.2s", width: small ? "auto" : "100%",
      letterSpacing:0.2, display:"flex", alignItems:"center", justifyContent:"center", gap:6 }}>
      {children}
    </button>
  );
}
function GhostBtn({ children, onClick, small, color }) {
  const c = color || T.green;
  return (
    <button onClick={onClick} style={{
      background:"transparent", color:c,
      border:`2px solid ${c}`, borderRadius: small ? 10 : 14,
      padding: small ? "7px 14px" : "13px 24px",
      fontSize: small ? 12 : 14, fontWeight:700, cursor:"pointer",
      transition:"all 0.2s", width: small ? "auto" : "100%",
      display:"flex", alignItems:"center", justifyContent:"center", gap:6 }}>
      {children}
    </button>
  );
}

