// ─────────────────────────────────────────────────────────────────────────────
// ─────────────────────────────────────────────────────────────────────────────
// MarqueeText — scrolls text horizontally when it overflows its container
// ─────────────────────────────────────────────────────────────────────────────
function MarqueeText({ text, style }) {
  const outerRef = useRef(null);
  const innerRef = useRef(null);
  const [dist, setDist] = useState(0);

  useEffect(() => {
    if (!outerRef.current || !innerRef.current) return;
    const overflow = innerRef.current.scrollWidth - outerRef.current.clientWidth;
    setDist(overflow > 4 ? -(overflow + 12) : 0);
  }, [text]);

  const duration = Math.max(2.5, Math.abs(dist) / 40);

  return (
    <div ref={outerRef} style={{ overflow:"hidden", whiteSpace:"nowrap" }}>
      <span
        ref={innerRef}
        style={{
          ...style,
          display:"inline-block",
          whiteSpace:"nowrap",
          animation: dist !== 0
            ? `taskMarquee ${duration}s ease-in-out infinite alternate`
            : "none",
          "--marquee-dist": `${dist}px`,
        }}
      >
        {text}
      </span>
    </div>
  );
}

// ─────────────────────────────────────────────────────────────────────────────
// src/components/PrepTaskRow  — swipe-to-complete row
// ─────────────────────────────────────────────────────────────────────────────
function PrepTaskRow({ task, onComplete, onDismiss, onUncomplete, showHint }) {
  const [offset,   setOffset]   = useState(0);
  const [dragging, setDragging] = useState(false);
  const [done,     setDone]     = useState(task._done || false);
  const [menuOpen,    setMenuOpen]    = useState(false);
  const [hintVisible, setHintVisible] = useState(true);
  useEffect(() => {
    if (!showHint) return;
    const t = setTimeout(() => setHintVisible(false), 2800);
    return () => clearTimeout(t);
  }, [showHint]);
  const startX = useRef(0);

  const onPointerDown = e => { startX.current = e.clientX; setDragging(true); e.currentTarget.setPointerCapture(e.pointerId); };
  const onPointerMove = e => { if (!dragging) return; setOffset(e.clientX - startX.current); };
  const onPointerUp   = () => {
    setDragging(false);
    if (offset > 80)  { setDone(true); setTimeout(onComplete, 450); }
    else if (offset < -80) { onDismiss(); }
    setOffset(0);
  };

  const priorityDot = { high: T.red, med: T.orange, low: T.inkLight };
  const priorityLabel = { high:"Alta", med:"Media", low:"Baja" };
  const showGreen = offset > 10;
  const showRed   = offset < -10;

  return (
    <div style={{ position:"relative", marginBottom:8, borderRadius:16, overflow:"hidden", marginLeft:8, marginRight:8 }}>
      {/* Swipe bg */}
      {showGreen && (
        <div style={{ position:"absolute", inset:0, background:T.green, borderRadius:16,
          display:"flex", alignItems:"center", paddingLeft:20 }}>
          <span style={{ color:"#fff", fontWeight:800, fontSize:13 }}>✓ Hecho</span>
        </div>
      )}
      {showRed && (
        <div style={{ position:"absolute", inset:0, background:T.red, borderRadius:16,
          display:"flex", alignItems:"center", justifyContent:"flex-end", paddingRight:20 }}>
          <span style={{ color:"#fff", fontWeight:800, fontSize:13 }}>✕ Omitir</span>
        </div>
      )}

      {/* Swipe affordance — animated tutorial, fades after 2.8s */}
      {showHint && hintVisible && !done && (
        <div style={{ position:"absolute", inset:0, borderRadius:16, zIndex:5,
          pointerEvents:"none", display:"flex", alignItems:"center",
          justifyContent:"space-between", padding:"0 8px",
          opacity: hintVisible ? 1 : 0,
          transition:"opacity 0.5s ease",
          animation:"fadeIn 0.4s ease" }}>
          <div style={{ display:"flex", alignItems:"center", gap:4,
            background:T.green, borderRadius:R.pill, padding:"5px 10px",
            boxShadow:EL.S,
            animation:"slideRight 0.6s ease 0.3s both" }}>
            <span style={{ color:"#fff", fontSize:13 }}>✓</span>
            <span style={{ color:"#fff", fontSize:12, fontWeight:700 }}>hecho →</span>
          </div>
          <div style={{ display:"flex", alignItems:"center", gap:4,
            background:T.red, borderRadius:R.pill, padding:"5px 10px",
            boxShadow:EL.S,
            animation:"slideLeft 0.6s ease 0.3s both" }}>
            <span style={{ color:"#fff", fontSize:12, fontWeight:700 }}>← omitir</span>
            <span style={{ color:"#fff", fontSize:13 }}>✕</span>
          </div>
        </div>
      )}

      {/* Foreground card */}
      <div
        onPointerDown={onPointerDown} onPointerMove={onPointerMove} onPointerUp={onPointerUp}
        style={{ position:"relative", background: done ? T.greenPale : T.card,
          borderRadius:16, padding:"12px 14px",
          border:`1px solid ${done ? T.green+"60" : T.border}`,
          transform:`translateX(${offset}px)`,
          transition: dragging ? "none" : "transform 0.35s cubic-bezier(0.34,1.56,0.64,1), background 0.3s",
          cursor:"grab", userSelect:"none", touchAction:"none",
          opacity: done ? 0.5 : 1, display:"flex", alignItems:"center", gap:10 }}>

        {/* Complete tap button — toggle done/undone, 44×44
            onPointerDown stops propagation so swipe never fires on button tap */}
        <button
          onPointerDown={e => e.stopPropagation()}
          onClick={() => {
            const next = !done;
            setDone(next);
            if (next) setTimeout(onComplete, 400);
            else if (onUncomplete) onUncomplete();
          }}
          aria-label={done ? `Desmarcar: ${task.text}` : `Marcar como hecho: ${task.text}`}
          style={{ width:44, height:44, borderRadius:R.pill,
            border:`2px solid ${done ? T.green : "#8faaa8"}`,
            background: done ? T.green : "transparent", flexShrink:0, cursor:"pointer",
            display:"flex", alignItems:"center", justifyContent:"center",
            fontSize:16, color:"#fff", transition:"all 0.25s",
            boxShadow: done ? EL.S : "none" }}>
          {done
            ? <span style={{ color:"#fff", fontWeight:800, fontSize:18 }}>✓</span>
            : <span style={{ color:"#8faaa8", fontSize:18 }}>○</span>
          }
        </button>

        {INGREDIENT_PHOTOS[task.id] ? (
          <div style={{ width:44, height:44, borderRadius:12, overflow:"hidden",
            flexShrink:0, border:`1px solid ${T.border}` }}>
            <img src={INGREDIENT_PHOTOS[task.id]} alt={task.text}
              style={{ width:"100%", height:"100%", objectFit:"cover", display:"block" }} />
          </div>
        ) : null}

        <div style={{ flex:1, minWidth:0 }}>
          <div style={{ overflow:"hidden", whiteSpace:"nowrap" }}>
            <MarqueeText
              text={task.text}
              style={{ fontSize:14, fontWeight:600, color:T.ink,
                textDecoration: done ? "line-through" : "none" }}
            />
          </div>
          <div style={{ fontSize:12, color:T.inkLight, marginTop:1 }}>{task.time}</div>
        </div>

        {/* Priority indicator: shape + color + text */}
        <div style={{ display:"flex", alignItems:"center", gap:4, flexShrink:0 }}>
          <div
            role="img"
            aria-label={`Prioridad ${priorityLabel[task.priority]}`}
            style={{ width:8, height:8,
              borderRadius: task.priority==="med" ? 99 : 2,
              background:priorityDot[task.priority] }} />
          <span style={{ fontSize:12, color:T.inkLight, fontWeight:600 }}>
            {priorityLabel[task.priority]}
          </span>
        </div>

        {/* Dismiss tap button — 44×44, stops pointer so no swipe conflict */}
        <button
          onPointerDown={e => e.stopPropagation()}
          onClick={e => { e.stopPropagation(); onDismiss(); }}
          aria-label={`Omitir tarea: ${task.text}`}
          style={{ width:44, height:44, borderRadius:99, border:"none",
            background:"transparent", cursor:"pointer",
            display:"flex", alignItems:"center", justifyContent:"center",
            color:T.inkLight, fontSize:18, fontWeight:300, flexShrink:0 }}>×</button>
      </div>

      {/* Accessible actions menu (hidden, exposed via button above) */}
    </div>
  );
}

// ─────────────────────────────────────────────────────────────────────────────
